   144→
   145→void HeaderParser::evaluateHeaders(Http::HeaderMap& headers,
   146→                                   const Formatter::HttpFormatterContext& context,
   147→                                   const StreamInfo::StreamInfo* stream_info) const {
   148→  // Removing headers in the headers_to_remove_ list first makes
   149→  // remove-before-add the default behavior as expected by users.
   150→  for (const auto& header : headers_to_remove_) {
   151→    headers.remove(header);
   152→  }
   153→
   154→  // Temporary storage to hold evaluated values of headers to add and replace. This is required
   155→  // to execute all formatters using the original received headers.
   156→  // Only after all the formatters produced the new values of the headers, the headers are set.
   157→  // absl::InlinedVector is optimized for 4 headers. After that it behaves as normal std::vector.
   158→  // It is assumed that most of the use cases will add or modify fairly small number of headers
   159→  // (<=4). If this assumption changes, the number of inlined capacity should be increased.
   160→  // header_formatter_speed_test.cc provides micro-benchmark for evaluating speed of adding and
   161→  // replacing headers and should be used when modifying the code below to access the performance
   162→  // impact of code changes.
   163→  absl::InlinedVector<std::pair<const Http::LowerCaseString&, const std::string>, 4> headers_to_add,
   164→      headers_to_overwrite;
   165→  // value_buffer is used only when stream_info is a valid pointer and stores header value
   166→  // created by a formatter. It is declared outside of 'for' loop for performance reason to avoid
   167→  // stack allocation and unnecessary std::string's memory adjustments for each iteration. The
   168→  // actual value of the header is accessed via 'value' variable which is initialized differently
   169→  // depending whether stream_info and valid or nullptr. Based on performance tests implemented in
   170→  // header_formatter_speed_test.cc this approach strikes the best balance between performance and
   171→  // readability.
   172→  std::string value_buffer;
   173→  for (const auto& [key, entry] : headers_to_add_) {
   174→    absl::string_view value;
   175→    if (stream_info != nullptr) {
   176→      value_buffer = entry->formatter_->formatWithContext(context, *stream_info);
   177→      value = value_buffer;
   178→    } else {
   179→      value = entry->original_value_;
   180→    }
   181→    if (!value.empty() || entry->add_if_empty_) {
   182→      switch (entry->append_action_) {
   183→        PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
   184→      case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
   185→        headers_to_add.emplace_back(key, value);
   186→        break;
   187→      case HeaderValueOption::ADD_IF_ABSENT:
   188→        if (auto header_entry = headers.get(key); header_entry.empty()) {
   189→          headers_to_add.emplace_back(key, value);
   190→        }
   191→        break;
   192→      case HeaderValueOption::OVERWRITE_IF_EXISTS:
   193→        if (headers.get(key).empty()) {
   194→          break;
   195→        }
   196→        FALLTHRU;
   197→      case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
   198→        headers_to_overwrite.emplace_back(key, value);
   199→        break;
   200→      }
   201→    }
   202→  }
   203→
   204→  // First overwrite all headers which need to be overwritten.
   205→  for (const auto& header : headers_to_overwrite) {
   206→    headers.setReferenceKey(header.first, header.second);
   207→  }
   208→
   209→  // Now add headers which should be added.
   210→  for (const auto& header : headers_to_add) {
   211→    headers.addReferenceKey(header.first, header.second);
   212→  }
   213→}
   214→
   215→Http::HeaderTransforms HeaderParser::getHeaderTransforms(const StreamInfo::StreamInfo& stream_info,
   216→                                                         bool do_formatting) const {
   217→  Http::HeaderTransforms transforms;
   218→
   219→  for (const auto& [key, entry] : headers_to_add_) {
   220→    if (do_formatting) {
   221→      const std::string value = entry->formatter_->formatWithContext({}, stream_info);
   222→      if (!value.empty() || entry->add_if_empty_) {
   223→        switch (entry->append_action_) {
   224→        case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
   225→          transforms.headers_to_append_or_add.push_back({key, value});
   226→          break;
   227→        case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
   228→          transforms.headers_to_overwrite_or_add.push_back({key, value});
   229→          break;
   230→        case HeaderValueOption::ADD_IF_ABSENT:
   231→          transforms.headers_to_add_if_absent.push_back({key, value});
   232→          break;
   233→        default:
   234→          break;
   235→        }
   236→      }
   237→    } else {
   238→      switch (entry->append_action_) {
   239→      case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
   240→        transforms.headers_to_append_or_add.push_back({key, entry->original_value_});
   241→        break;
   242→      case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
   243→        transforms.headers_to_overwrite_or_add.push_back({key, entry->original_value_});
   244→        break;
   245→      case HeaderValueOption::ADD_IF_ABSENT:
   246→        transforms.headers_to_add_if_absent.push_back({key, entry->original_value_});
   247→        break;
   248→      default:
   249→        break;
   250→      }
   251→    }
   252→  }
   253→
   254→  transforms.headers_to_remove = headers_to_remove_;
   255→
   256→  return transforms;
   257→}
   258→
   259→} // namespace Router
   260→} // namespace Envoy
