    15→void QueryParameterMutationAppend::mutateQueryParameter(
    16→    Http::Utility::QueryParamsMulti& params, const Formatter::HttpFormatterContext& context,
    17→    const StreamInfo::StreamInfo& stream_info) const {
    18→
    19→  switch (action_) {
    20→    PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
    21→  case ParameterAppendProto::APPEND_IF_EXISTS_OR_ADD:
    22→    params.add(key_, formatter_->formatWithContext(context, stream_info));
    23→    return;
    24→  case ParameterAppendProto::ADD_IF_ABSENT: {
    25→    auto iter = params.data().find(key_);
    26→    if (iter == params.data().end()) {
    27→      params.add(key_, formatter_->formatWithContext(context, stream_info));
    28→    }
    29→    break;
    30→  }
    31→  case ParameterAppendProto::OVERWRITE_IF_EXISTS: {
    32→    auto iter = params.data().find(key_);
    33→    if (iter != params.data().end()) {
    34→      params.overwrite(key_, formatter_->formatWithContext(context, stream_info));
    35→    }
    36→    break;
    37→  }
    38→  case ParameterAppendProto::OVERWRITE_IF_EXISTS_OR_ADD:
    39→    params.overwrite(key_, formatter_->formatWithContext(context, stream_info));
    40→    break;
    41→  }
    42→}
