    44→Mutations::Mutations(const MutationsProto& config, absl::Status& creation_status) {
    45→  auto request_mutations_or_error = HeaderMutations::create(config.request_mutations());
    46→  SET_AND_RETURN_IF_NOT_OK(request_mutations_or_error.status(), creation_status);
    47→  request_mutations_ = std::move(request_mutations_or_error.value());
    48→
    49→  auto response_mutations_or_error = HeaderMutations::create(config.response_mutations());
    50→  SET_AND_RETURN_IF_NOT_OK(response_mutations_or_error.status(), creation_status);
    51→  response_mutations_ = std::move(response_mutations_or_error.value());
    52→
    53→  auto response_trailers_mutations_or_error =
    54→      HeaderMutations::create(config.response_trailers_mutations());
    55→  SET_AND_RETURN_IF_NOT_OK(response_trailers_mutations_or_error.status(), creation_status);
    56→  response_trailers_mutations_ = std::move(response_trailers_mutations_or_error.value());
    57→
    58→  auto request_trailers_mutations_or_error =
    59→      HeaderMutations::create(config.request_trailers_mutations());
    60→  SET_AND_RETURN_IF_NOT_OK(request_trailers_mutations_or_error.status(), creation_status);
    61→  request_trailers_mutations_ = std::move(request_trailers_mutations_or_error.value());
    62→
    63→  query_query_parameter_mutations_.reserve(config.query_parameter_mutations_size());
    64→  for (const auto& mutation : config.query_parameter_mutations()) {
    65→    if (mutation.has_append()) {
    66→      if (!mutation.remove().empty()) {
    67→        creation_status =
    68→            absl::InvalidArgumentError("Only one of 'append'/'remove can be specified.");
    69→        return;
    70→      }
    71→
    72→      if (!mutation.append().has_record()) {
    73→        creation_status = absl::InvalidArgumentError("No record specified for append mutation.");
    74→        return;
    75→      }
    76→      if (!mutation.append().record().value().has_string_value()) {
    77→        creation_status =
    78→            absl::InvalidArgumentError("Only string value is allowed for record value.");
    79→        return;
    80→      }
    81→
    82→      auto value_or_error =
    83→          Formatter::FormatterImpl::create(mutation.append().record().value().string_value(), true);
    84→      SET_AND_RETURN_IF_NOT_OK(value_or_error.status(), creation_status);
    85→      query_query_parameter_mutations_.emplace_back(std::make_unique<QueryParameterMutationAppend>(
    86→          mutation.append().record().key(), std::move(value_or_error.value()),
    87→          mutation.append().action()));
    88→
    89→    } else if (!mutation.remove().empty()) {
    90→      query_query_parameter_mutations_.emplace_back(
    91→          std::make_unique<QueryParameterMutationRemove>(mutation.remove()));
    92→    } else {
    93→      creation_status = absl::InvalidArgumentError("One of 'append'/'remove' must be specified.");
    94→      return;
    95→    }
    96→  }
