    99→void Mutations::mutateRequestHeaders(Http::RequestHeaderMap& headers,
   100→                                     const Formatter::HttpFormatterContext& context,
   101→                                     const StreamInfo::StreamInfo& stream_info) const {
   102→  request_mutations_->evaluateHeaders(headers, context, stream_info);
   103→
   104→  if (query_query_parameter_mutations_.empty() || headers.Path() == nullptr) {
   105→    return;
   106→  }
   107→
   108→  // Mutate query parameters.
   109→  Http::Utility::QueryParamsMulti params =
   110→      Http::Utility::QueryParamsMulti::parseAndDecodeQueryString(headers.getPathValue());
   111→  for (const auto& mutation : query_query_parameter_mutations_) {
   112→    mutation->mutateQueryParameter(params, context, stream_info);
   113→  }
   114→  headers.setPath(params.replaceQueryString(headers.Path()->value()));
   115→}
